try {

    const fields = String(msg.payload).split(",");

    if (fields.length < 15) {
        const m = `Processed CSV: bad field count (got ${fields.length}, expected 15). Row dropped.`;
        node.warn(m);
        sendLog("warn", m);
        return null;
    }

    // Column order (timestamp already stripped by Strip Timestamp):
    // [0]=rpm [1]=amp [2]=volt [3]=trq [4]=mode
    // [5]=err [6]=warn [7]=igbt_c [8]=mot_c
    // [9]=l_regen [10]=l_err [11]=l_warn [12]=l_ok [13]=l_pump [14]=drive_ena

    msg.params = [
        msg.timestamp,
        parseNum(fields[0]),   // rpm
        parseNum(fields[1]),   // amp
        parseNum(fields[2]),   // volt
        parseNum(fields[3]),   // trq
        parseInt_(fields[4]),  // mode
        parseInt_(fields[5]),  // err
        parseInt_(fields[6]),  // warn
        parseNum(fields[7]),   // igbt_c
        parseNum(fields[8]),   // mot_c
        parseBool(fields[9]),  // l_regen
        parseBool(fields[10]), // l_err
        parseBool(fields[11]), // l_warn
        parseBool(fields[12]), // l_ok
        parseBool(fields[13]), // l_pump
        parseBool(fields[14]), // drive_ena
        null                   // healed_fields (not applicable for import)
    ];

    msg.payload = msg.params;
    return msg;

    // -----------------------------------------
    // Defining Functions
    // -----------------------------------------

    function parseNum(v) {
        const n = parseFloat(v);
        return isNaN(n) ? null : n;
    }

    function parseInt_(v) {
        const n = parseInt(v, 10);
        return isNaN(n) ? null : n;
    }

    function parseBool(v) {
        const s = String(v).trim().toLowerCase();
        if (s === "true"  || s === "t" || s === "1") return true;
        if (s === "false" || s === "f" || s === "0") return false;
        return null;
    }

    function sendLog(level, message) {
        node.send([null, {
            payload: {
                time:    msg.timestamp,
                level:   level,
                node:    "Parse Processed CSV",
                message: message,
                fields:  null
            }
        }]);
    }

} catch (error) {
    node.error(`Critical Failure in 'Parse Processed CSV': ${error.message}`, msg);
    return null;
