// ════════════════════════════════════════════════════════════
// RANDOM CONTINUOUS DRIVING SIMULATOR
// Click inject → one self-paced cycle → stop.
// Status line is fixed-width — bar position and length never shift.
// ════════════════════════════════════════════════════════════

var TICK_MS = 300;
var BAR_WIDTH = 12;

function clamp(v, lo, hi) { return Math.max(lo, Math.min(hi, v)); }
function noise(amp) { return (Math.random() * 2 - 1) * amp; }
function approach(cur, tgt, step) { return cur + clamp(tgt - cur, -step, step); }

// Fixed-width bar using true block-element chars (same glyph width)
function makeBar(pct) {
    var filled = Math.round((pct / 100) * BAR_WIDTH);
    if (filled < 0) filled = 0;
    if (filled > BAR_WIDTH) filled = BAR_WIDTH;
    return "[" + "█".repeat(filled) + "░".repeat(BAR_WIDTH - filled) + "]";
}

// Always 4 chars: "  0%" … " 42%" … "100%"
function padPct(pct) {
    var s = Math.round(pct) + "%";
    while (s.length < 4) s = " " + s;
    return s;
}

// Always 6 chars (longest phase name is "CRUISE")
function padPhase(name) {
    var s = name;
    while (s.length < 6) s = s + " ";
    return s;
}

function buildPhaseList() {
    return [
        { name: "IDLE", dur: 1.5 + Math.random() * 1.5 },
        { name: "ACCEL", dur: 5 + Math.random() * 4 },
        { name: "CRUISE", dur: 4 + Math.random() * 5 },
        { name: "COAST", dur: 2 + Math.random() * 2 },
        { name: "REGEN", dur: 3 + Math.random() * 3 },
        { name: "STOP", dur: 1.5 + Math.random() * 1.5 }
    ];
}

// Kill previous run
var oldHandle = context.get("handle");
if (oldHandle) { clearInterval(oldHandle); context.set("handle", null); }

// Fresh state
var phaseList = buildPhaseList();
var totalDur = phaseList.reduce(function (a, p) { return a + p.dur; }, 0);

var s = {
    startMs: Date.now(), lastMs: Date.now(), elapsed: 0,
    phaseList: phaseList,
    totalDur: totalDur,
    phaseIdx: 0,
    phase: phaseList[0].name,
    phaseStartSec: 0,
    phaseDurSec: phaseList[0].dur,
    rpm: 0, targetRpm: 0,
    amp: 0, trq: 0,
    volt: 19660, igbtC: 19739, motC: 11644,
    L_REGEN: 0, warn: 0, err: 0,
    done: false
};
context.set("state", s);
node.status({
    fill: "blue", shape: "dot",
    text: makeBar(0) + " " + padPct(0) + " " + padPhase(s.phase)
});

var handle = setInterval(function () {
    var s = context.get("state");
    if (!s || s.done) {
        clearInterval(handle);
        context.set("handle", null);
        if (s) node.status({
            fill: "grey", shape: "dot",
            text: makeBar(100) + " " + padPct(100) + " " + padPhase("DONE")
        });
        return;
    }

    var now = Date.now();
    var dt = (now - s.lastMs) / 1000;
    if (dt <= 0) dt = 0.001;
    if (dt > 1.0) dt = 1.0;
    s.lastMs = now;
    s.elapsed = (now - s.startMs) / 1000;

    while (!s.done && s.elapsed >= s.phaseStartSec + s.phaseDurSec) {
        s.phaseStartSec += s.phaseDurSec;
        s.phaseIdx++;
        if (s.phaseIdx >= s.phaseList.length) { s.done = true; break; }
        s.phase = s.phaseList[s.phaseIdx].name;
        s.phaseDurSec = s.phaseList[s.phaseIdx].dur;
        switch (s.phase) {
            case "ACCEL": s.targetRpm = 12000 + Math.floor(Math.random() * 20000); break;
            case "CRUISE": s.targetRpm = s.rpm + Math.floor(noise(1500)); break;
            case "COAST": s.targetRpm = Math.floor(s.rpm * 0.6); break;
            case "REGEN": s.targetRpm = 0;
                s.L_REGEN = 1 + Math.floor(Math.random() * 3); break;
            case "STOP": s.targetRpm = 0; s.L_REGEN = 0; break;
        }
    }

    if (s.done) {
        context.set("state", s);
        clearInterval(handle);
        context.set("handle", null);
        node.status({
            fill: "grey", shape: "dot",
            text: makeBar(100) + " " + padPct(100) + " " + padPhase("DONE")
        });
        return;
    }

    // ── Physics ──
    var rpmRate = (s.phase === "REGEN" || s.phase === "COAST") ? 6000 : 5000;
    s.rpm = approach(s.rpm, s.targetRpm, rpmRate * dt) + noise(250 * Math.sqrt(dt));
    s.rpm = clamp(Math.round(s.rpm), -32767, 32767);

    switch (s.phase) {
        case "IDLE": case "STOP":
            s.amp = Math.round(noise(400)); s.trq = Math.round(noise(400)); s.L_REGEN = 0; break;
        case "ACCEL":
            s.amp = clamp(Math.round(18000 + noise(3500) - Math.abs(s.rpm) * 0.2), 0, 32767);
            s.trq = clamp(Math.round(22000 + noise(3500) - Math.abs(s.rpm) * 0.3), 0, 32767);
            s.L_REGEN = 0; break;
        case "CRUISE":
            s.amp = clamp(Math.round(5000 + noise(1800)), 0, 32767);
            s.trq = clamp(Math.round(4000 + noise(1800)), 0, 32767);
            s.L_REGEN = 0; break;
        case "COAST":
            s.amp = Math.round(noise(700)); s.trq = Math.round(noise(700));
            s.L_REGEN = 0; break;
        case "REGEN":
            var rg = 4000 * s.L_REGEN;
            s.amp = clamp(Math.round(-rg + noise(1200)), -32767, 0);
            s.trq = clamp(Math.round(-rg * 1.7 + noise(1200)), -32767, 0);
            break;
    }

    var voltTarget = 19660 - (s.amp / 32767) * 3000 + noise(120);
    s.volt = clamp(Math.round(approach(s.volt, voltTarget, 1500 * dt)), 0, 32767);

    var loadFactor = Math.abs(s.amp) / 32767;
    var heatRate = loadFactor * 30;
    var coolRate = 8;
    s.igbtC += (heatRate - coolRate) * dt + noise(15 * Math.sqrt(dt));
    s.motC += (heatRate * 0.6 - coolRate * 0.5) * dt + noise(10 * Math.sqrt(dt));
    s.igbtC = clamp(Math.round(s.igbtC), 18387, 28000);
    s.motC = clamp(Math.round(s.motC), 11446, 16500);

    s.warn = 0; s.err = 0;
    if (s.igbtC >= 24775) s.warn |= 1;
    if (Math.abs(s.amp) > 28000) s.warn |= 2;
    if (Math.random() < 0.005) s.warn |= 256;
    if (s.igbtC >= 26702) { s.err = 8; s.rpm = 0; s.amp = 0; s.trq = 0; }

    var L_OK = (s.err === 0) ? 1 : 0;
    var L_ERR = (s.err !== 0) ? 1 : 0;
    var L_WARN = (s.warn !== 0) ? 1 : 0;
    var L_PUMP = (s.igbtC >= 21357 || s.motC >= 12747) ? 1 : 0;
    var drive_ena = (s.err === 0) ? 1 : 0;

    context.set("state", s);

    node.send({
        payload: [
            s.rpm, s.amp, s.volt, s.trq, "D",
            s.igbtC, s.motC, s.err, s.warn,
            s.L_REGEN, L_ERR, L_WARN, L_OK, L_PUMP, drive_ena
        ].join(",")
    });

    var pct = clamp((s.elapsed / s.totalDur) * 100, 0, 100);

    node.status({
        fill: (s.err ? "red" : (s.warn ? "yellow" : "green")),
        shape: "dot",
        text: makeBar(pct) + " " + padPct(pct) + " " + padPhase(s.phase)
    });
}, TICK_MS);

context.set("handle", handle);
return null;

try {

    // Stamp the frame immediately so every warning shares the same timestamp.
    msg.timestamp = msg.timestamp || new Date().toISOString();

    // Parse the 15-field CSV frame. 
    const rawDataFrame = String(msg.payload).split(",");

    // If any required field is missing, drop the frame with a clear warning.
    if (rawDataFrame.length !== 15) {
        const m = `Bad frame: got ${rawDataFrame.length} fields, expected 15. This frame is dropped.`;
        node.warn(m);
        sendLog("warn", m);
        return null;
    }

    // Mode (rawDataFrame[4]) is checked separately because it is expected as a string. 
    // It defaults to an empty string in case there's no value.
    // It trims spaces just in case.
    const mode = String(rawDataFrame[4] ?? "").trim();
    if (!mode) {
        const m = "Missing mode. This frame is dropped.";
        node.warn(m);
        sendLog("warn", m);
        return null;
    }

    // Mark all the numeric fields. 
    const numericFields = [
        ["rpm", 0], ["amp", 1], ["volt", 2], ["trq", 3],
        ["igbtC", 5], ["motC", 6], ["err", 7], ["warn", 8],
        ["L_REGEN", 9], ["L_ERR", 10], ["L_WARN", 11], ["L_OK", 12],
        ["L_PUMP", 13], ["drive_ena", 14]
    ];

    // Build into a local sandbox. Only commit to msg.raw if every field passes.
    // 'Mode' is already checked, so it is immediately thrown in.
    const raw = { mode };
    // Process other telemetry fields sequentially using the mapping checklist.
    for (const [name, idx] of numericFields) {
        const value = pick(idx, name);
        if (value === null) return null;
        // Put the verified values into the output object.
        raw[name] = value;
    }

    // Every field is valid. Commit the sandbox to the message.
    msg.raw = raw;

    return msg;


    // -----------------------------------------
    // Defining Functions
    // -----------------------------------------

    // pick: Parses a numeric field, warns and returns null if invalid.
    function pick(idx, name) {
        const raw = rawDataFrame[idx];
        // Check if it's undefined or if there is no value.
        if (raw === undefined || raw === "") {
            const m = `Missing field: ${name}. This frame is dropped.`;
            node.warn(m);
            sendLog("warn", m);
            return null;
        }
        // Before this, all of them are strings. Try converting them into numbers. If it's not a number, it will be NaN.
        const rawNumber = Number(raw);

        // Check if it is a number. If not (NaN), then drop it.
        if (Number.isNaN(rawNumber)) {
            const m = `Bad ${name}: ${JSON.stringify(raw)} is not a number. This frame is dropped.`;
            node.warn(m);
            sendLog("warn", m);
            return null;
        }
        // Everything is fine, return the number. 
        return rawNumber;
    }

    function sendLog(level, message) {
        node.send([null, {
            payload: {
                time: msg.timestamp,
                level: level,
                node: "Parse CSV",
                message: message,
                fields: null
            }
        }]);
    }

} catch (error) {

    // For this part, these are critical unknown errors, so it's best if we just drop the entire frame. No healing. Fix the bug.
    node.error(`Critical Failure in 'Parse CSV' Node: ${error.message}. This frame is dropped.`, msg);
    return null;

}

try {

    // Creating a container.
    msg.real = {};

    // Throw in timestamp.
    msg.real.time = msg.timestamp;

    // Scale raw 0–32767 values for rpm/amp/volt/trq in real-world units.
    const RAW_MAX = 32767;
    const RAW_MIN = -32767;

    // Divide the incoming raw number by the absolute maximum possible raw number to obtain the percentage.
    // Then, multiply the percentage with the real-world limit to obtain the real-world reading. 

    // rpm is rounded to the nearest whole number to prevent fake precision.
    msg.real.rpm = validateRaw(msg.raw.rpm, "rpm") ? Math.round((msg.raw.rpm / RAW_MAX) * 5500) : null;

    // The rest are rounded to 1 decimal point. '+' returns value as 'number'.
    msg.real.amp = validateRaw(msg.raw.amp, "amp") ? +((msg.raw.amp / RAW_MAX) * 212.1).toFixed(1) : null;
    msg.real.volt = validateRaw(msg.raw.volt, "volt") ? +((msg.raw.volt / RAW_MAX) * 200).toFixed(1) : null;
    msg.real.trq = validateRaw(msg.raw.trq, "trq") ? +((msg.raw.trq / RAW_MAX) * 125).toFixed(1) : null;

    return msg;

    // -----------------------------------------
    // Defining Functions
    // -----------------------------------------


    // Helper function to validate, log errors to the database, and trigger null assignment
    function validateRaw(val, fieldName) {
        if (typeof val === 'number' && val >= RAW_MIN && val <= RAW_MAX) {
            return true;
        }
        // If validation fails...
        const m = `Mapping Error: Received invalid raw ${fieldName} ["${val}"]. Passing null forward.`;
        node.warn(m);
        sendLog("warn", m);
        return false;
    }

    function sendLog(level, message) {
        node.send([null, {
            payload: {
                time: msg.timestamp,
                level: level,
                node: "Raw to Real Conversion",
                message: message,
                fields: null
            }
        }]);
    }

} catch (error) {

    // For this part, these are critical unknown errors, so it's best if we just drop the entire frame. No healing. Fix the bug.
    node.error(`Critical Failure in 'Raw to Real Conversion' Node: ${error.message}. This frame is dropped.`, msg);
    return null;

}

try {

    // IGBT table reference
    const IGBT_TABLE = [
        [16308, -30], [16387, -25], [16487, -20], [16609, -15], [16757, -10],
        [16938, -5], [17151, 0], [17400, 5], [17688, 10], [18017, 15],
        [18387, 20], [18797, 25], [19247, 30], [19733, 35], [20250, 40],
        [20793, 45], [21357, 50], [21933, 55], [22515, 60], [23097, 65],
        [23671, 70], [24232, 75], [24775, 80], [25296, 85], [25792, 90],
        [26261, 95], [26702, 100], [27114, 105], [27497, 110], [27851, 115],
        [28179, 120], [28480, 125]
    ];

    // IGBT temp: 32-point lookup table + linear interpolation
    msg.real.igbt_c = calculateIgbtTemp(msg.raw.igbtC);

    // Motor temp: two-point linear fit (raw 11446 = 30°C, raw 16000 = 100°C).
    msg.real.mot_c = calculateMotorTemp(msg.raw.motC);


    return msg;

    // -----------------------------------------
    // Defining Functions
    // -----------------------------------------

    function calculateIgbtTemp(rawIgbtValue) {
        if (rawIgbtValue < IGBT_TABLE[0][0] || rawIgbtValue > IGBT_TABLE[IGBT_TABLE.length - 1][0]) {
            const m = `Out of range: igbt_c raw value ${rawIgbtValue} is outside the lookup table. Passing null forward.`;
            node.warn(m);
            sendLog("warn", m);
            return null;
        }
        for (let i = 0; i < IGBT_TABLE.length - 1; i++) {
            const [x0, y0] = IGBT_TABLE[i], [x1, y1] = IGBT_TABLE[i + 1];
            if (rawIgbtValue >= x0 && rawIgbtValue <= x1) return +(y0 + (rawIgbtValue - x0) * (y1 - y0) / (x1 - x0)).toFixed(2);
        }
        const m = `Calculation Error: igbt_c raw value [${rawIgbtValue}] fell through a table gap or is NaN.`;
        node.warn(m);
        sendLog("warn", m);
        return null;
    }

    function calculateMotorTemp(rawMotorValue) {
        if (rawMotorValue < 10000 || rawMotorValue > 20000) {
            const m = `Out of range: mot_c raw value ${rawMotorValue} is outside the expected range. Passing null forward.`;
            node.warn(m);
            sendLog("warn", m);
            return null;
        }
        const x1 = 11446, y1 = 30, x2 = 16000, y2 = 100;
        return +(y1 + (rawMotorValue - x1) * (y2 - y1) / (x2 - x1)).toFixed(2);
    }

    function sendLog(level, message) {
        node.send([null, {
            payload: {
                time: msg.timestamp,
                level: level,
                node: "Temperature Conversion",
                message: message,
                fields: null
            }
        }]);
    }

} catch (error) {

    // For this part, these are critical unknown errors, so it's best if we just drop the entire frame. No healing. Fix the bug.
    node.error(`Critical Failure in 'Temperature Conversion' Node: ${error.message}. This frame is dropped.`, msg);
    return null;

}

try {
    // Strict Binary Flag Type Conversion
    const flagKeys = ['L_REGEN', 'L_ERR', 'L_WARN', 'L_OK', 'L_PUMP', 'drive_ena'];

    // Start a loop that steps through the checklist one flag at a time
    for (const key of flagKeys) {
        const rawValue = msg.raw[key];
        const outputKey = key.toLowerCase(); // maps 'L_REGEN' to 'l_regen'

        if (rawValue === 0) {
            msg.real[outputKey] = false;
        } else if (rawValue === 1) {
            msg.real[outputKey] = true;
        } else {
            // No healing. If it is corrupted, set to null and alert the DB.
            const m = `Mapping Error: Corrupted binary signal on flag [${key}] = "${rawValue}". Passing null forward.`;
            node.warn(m);
            sendLog("error", m);

            msg.real[outputKey] = null;
        }
    }

    return msg;

    // -----------------------------------------
    // Defining Functions
    // -----------------------------------------

    function sendLog(level, message) {
        node.send([null, {
            payload: {
                time: msg.timestamp,
                level: level,
                node: "Flags",
                message: message,
                fields: null // No fields were healed, so we pass null to the DB
            }
        }]);
    }

} catch (error) {
    // For this part, these are critical unknown errors, so it's best if we just drop the entire frame.
    node.error(`Critical Failure in 'Flags' Node: ${error.message}. This frame is dropped.`, msg);
    return null;
}

try {

    // 1. Fetch the entire last known good snapshot of the car from memory.
    const defaults = { rpm: 0, amp: 0.0, volt: 0.0, trq: 0.0, igbt_c: 0.00, mot_c: 0.00, mode: 0 };
    // Put in defaults first, then replace the ones exist in snapshot to prevent error from later fields being null.
    let history = { ...defaults, ...(context.get("carHistorySnapshot") ?? {}) };

    const r = msg.real;

    // 2. Initialize as an ARRAY so it passes down the wire cleanly
    msg.healedFields = [];

    // 3. Numerical Boundaries Checklist
    const ranges = {
        rpm: [-6000, 6000],
        amp: [-250, 250],
        volt: [-250, 250],
        trq: [-150, 150],
        igbt_c: [-40, 200],
        mot_c: [-40, 200],
        mode: [0, 2],       // 0 = Neutral, 1 = Drive, 2 = Reverse
    };

    // 4. Scan and heal numerical metrics
    for (const k of Object.keys(ranges)) {
        const [lo, hi] = ranges[k];

        if (Number.isNaN(r[k]) || r[k] === undefined || r[k] === null || r[k] < lo || r[k] > hi) {
            const m = `Glitch caught: ${k} = ${r[k]} → healed from history (${history[k]}).`;
            node.warn(m);

            // Push the healed field name into the array
            msg.healedFields.push(k);
            r[k] = history[k];   // Heal using history
        } else {
            history[k] = r[k];   // Update history pad
        }
    }

    // 5. Save the complete vehicle snapshot back to node memory.
    context.set("carHistorySnapshot", history);

    // 6. If any fields were healed, send ONE summary entry to the DB log table.
    if (msg.healedFields.length > 0) {
        const m = `Healed ${msg.healedFields.length} field(s): [${msg.healedFields.join(", ")}]`;
        node.warn(m);
        sendLog("warn", m, msg.healedFields);
    }

    return msg;

    // -----------------------------------------
    // Defining Functions
    // -----------------------------------------

    function sendLog(level, message, fields = null) {
        node.send([null, {
            payload: {
                time: msg.timestamp,
                level: level,
                // Updated node name to reflect the split
                node: "Heal",
                message: message,
                fields: fields
            }
        }]);
    }

} catch (error) {

    // Updated node name to reflect the split
    node.error(`Critical Failure in 'Heal' Node: ${error.message}. This frame is dropped.`, msg);
    return null;

}

try {

    const MODE_MAP = { D: 1, R: 2, N: 0 };

    // If the gear character is valid, map it to its ID.
    if (msg.raw.mode !== undefined && msg.raw.mode in MODE_MAP) {
        msg.real.mode = MODE_MAP[msg.raw.mode];
    } else {
        // Alert the pit wall if garbage data slips into the gear register.
        const m = `Mapping Error: Received invalid Drive Mode character ["${msg.raw.mode}"]. Passing null forward.`;
        node.warn(m);
        sendLog("warn", m);
        msg.real.mode = null;
    }

    return msg;

    // -----------------------------------------
    // Defining Functions
    // -----------------------------------------

    function sendLog(level, message) {
        node.send([null, {
            payload: {
                time: msg.timestamp,
                level: level,
                node: "Map Mode",
                message: message,
                fields: null
            }
        }]);
    }

} catch (error) {

    // For this part, these are critical unknown errors, so it's best if we just drop the entire frame. No healing. Fix the bug.
    node.error(`Critical Failure in 'Map Mode' Node: ${error.message}. This frame is dropped.`, msg);
    return null;

}

try {

    // PATH A: If this message was intercepted by the global 'catch' node
    if (msg.error) {
        msg.params = [
            msg.timestamp || new Date().toISOString(),  
            // Probably code-related error, so the content in 'try' wouldn't execute for that node.
            "critical",                                
            msg.error.source?.name || "Unknown Block",   
            `CRASH: ${msg.error.message}`,              
            null                                        
        ];
    }
    // PATH B: Standard manual log coming from Output Port 2 nodes 
    else if (msg.payload && msg.payload.level) {
        msg.params = [
            msg.payload.time,
            msg.payload.level,
            msg.payload.node,
            msg.payload.message,
            msg.payload.fields
        ];
    }
    // PATH C: Safety valve for unexpected message formats 
    else {
        node.error("'Normalize Log Event' node received an unrecognized message payload shape.");
        return null;
    }

    return msg;

} catch (error) {

    node.error(`Error inside 'Normalize Log Event' node: ${error.message}`, msg);
    return null;

}

try {
    const r = msg.real;

    // Safely extract the healed fields array (defaults to an empty array if undefined)
    const healedFields = msg.healedFields || [];

    msg.params = [
        r.time,
        r.rpm, r.amp, r.volt, r.trq,
        r.mode, 
        r.err, r.warn,   
        r.igbt_c, r.mot_c,
        r.l_regen, r.l_err, r.l_warn, r.l_ok, r.l_pump, r.drive_ena,
        // Send the array to PostgreSQL if it has items, otherwise send null
        healedFields.length > 0 ? healedFields : null  

    ];

    // For debug-panel visibility only.
    msg.payload = r;

    return msg;

} catch (error) {

    node.error(`Critical Failure in 'Build Parameters' Node: ${error.message}. This frame is dropped.`, msg);
    return null;

}

try {

    // Validate err
    const rawErr = msg.raw.err;
    if (typeof rawErr !== "number" || !Number.isInteger(rawErr) || rawErr < 0 || rawErr > 65535) {
        const m = `Invalid err bitmask: "${rawErr}". Setting to null.`;
        node.warn(m);
        sendLog("error", m);
        msg.real.err = null;
    } else {
        msg.real.err = rawErr;
    }

    // Validate warn
    const rawWarn = msg.raw.warn;
    if (typeof rawWarn !== "number" || !Number.isInteger(rawWarn) || rawWarn < 0 || rawWarn > 65535) {
        const m = `Invalid warn bitmask: "${rawWarn}". Setting to null.`;
        node.warn(m);
        sendLog("error", m);
        msg.real.warn = null;
    } else {
        msg.real.warn = rawWarn;
    }

    return msg;

    // -----------------------------------------
    // Defining Functions
    // -----------------------------------------

    function sendLog(level, message) {
        node.send([null, {
            payload: {
                time:    msg.timestamp,
                level:   level,
                node:    "Validate Bitmasks",
                message: message,
                fields:  null
            }
        }]);
    }

} catch (error) {
    node.error(`Critical Failure in 'Validate Bitmasks': ${error.message}`, msg);
    return null;
}

try {

    const fields = String(msg.payload).split(",");
    const isFirstRow = msg.parts && msg.parts.index === 0;

    // Reset the flag at the start of each new CSV file.
    if (isFirstRow) {
        context.set("noTsLogSent", false);
    }

    if (fields.length >= 16) {
        // ── Raw CSV path ──
        // Timestamp is field 0. Strip it and pass fields 1–15 forward.
        const ts = fields[0].trim();
        const parsed = ts ? new Date(ts) : null;
        const isValid = parsed && !isNaN(parsed.getTime());

        if (isValid) {
            // Good timestamp — use it and update tracker.
            msg.timestamp = parsed.toISOString();
            context.set("synthTime", parsed.getTime());
        } else {
            const m = ts
                ? `Corrupted timestamp: "${ts}" — Dropped the frame.`
                : "Blank timestamp field — Dropped the frame.";
            node.warn(m);
            sendLog("warn", m);
            return null;
        }

        msg.payload = fields.slice(1, 16).join(",");

    } else if (fields.length === 15) {
        // ── Real-time path (serial / MQTT) ──
        // No timestamp in data. First message gets system time,
        // every subsequent message gets last assigned + 300ms.
        const lastAssigned = context.get("lastAssignedTime");

        if (!lastAssigned) {
            // First message — seed with actual system time.
            const now = Date.now();
            msg.timestamp = new Date(now).toISOString();
            context.set("lastAssignedTime", now);
        } else {
            // All subsequent messages — always +300ms.
            const next = lastAssigned + 300;
            msg.timestamp = new Date(next).toISOString();
            context.set("lastAssignedTime", next);
        }

        // If this came from a CSV file with no timestamp column, log once.
        if (msg.parts && !context.get("noTsLogSent")) {
            const m = "No timestamp column in CSV — stamping rows with system arrival time.";
            node.warn(m);
            sendLog("warn", m);
            context.set("noTsLogSent", true);
        }

    }

    return msg;

    // -----------------------------------------
    // Defining Functions
    // -----------------------------------------

    function healCsvTimestamp() {
        const last = context.get("synthTime");
        if (last) {
            const healed = last + 300;
            context.set("synthTime", healed);
            return new Date(healed).toISOString();
        }
        // No previous valid timestamp — fall back to system time.
        return new Date().toISOString();
    }

    function sendLog(level, message) {
        node.send([null, {
            payload: {
                time: new Date().toISOString(),
                level: level,
                node: "Strip Timestamp",
                message: message,
                fields: null
            }
        }]);
    }

} catch (error) {
    node.error(`Critical Failure in 'Strip Timestamp': ${error.message}`, msg);
    return null;
}
